theorem example_89 (f : Polynomial ℂ) (t : ℂ) (s : ℂ)
    (hf_deg : f.degree = 3) (hf_no_mult : ∀ z, f.derivative.eval z ≠ 0) (hs : s ^ 2 = f.eval t) :
    let U := fun z => z - t;
    let V := fun z => s;
    let W := fun z => (f.eval z - f.eval t) / (z - t);
    (deriv U) = V ∧
    (deriv V) = (fun z => (t / 2) * (W 0 - W z) / z - W 0 / 2 + t * (z - t)) ∧
    (deriv W) = (fun z => s * (W 0 - W z) / z - s * t)

